Voici la liste des 11 catégories majeures sous forme d’une liste JSON, avec pour chacune un nom canonique (name) et une description explicite (description) :
jsonCopier le code[
  {
    "name": "create",
    "description": "Produire ou générer un nouvel élément, qu'il soit matériel, logique, visuel ou structurel."
  },
  {
    "name": "filter",
    "description": "Isoler, trier ou sélectionner des éléments en fonction de critères définis."
  },
  {
    "name": "search",
    "description": "Explorer un espace d'information pour trouver un ou plusieurs éléments correspondant à une intention ou une requête."
  },
  {
    "name": "store",
    "description": "Conserver, enregistrer ou archiver une donnée, un objet ou un état dans un espace dédié."
  },
  {
    "name": "display",
    "description": "Rendre un élément visible, compréhensible ou interprétable sous une forme lisible ou exploitable."
  },
  {
    "name": "modify",
    "description": "Transformer, corriger, adapter ou réorganiser un élément existant sans en changer la nature fondamentale."
  },
  {
    "name": "interact",
    "description": "Échanger, collaborer ou établir une relation entre entités (humaines, logicielles ou IA)."
  },
  {
    "name": "judge",
    "description": "Évaluer, comparer, noter ou analyser une donnée ou un comportement selon un ou plusieurs critères."
  },
  {
    "name": "maintain",
    "description": "Assurer la stabilité, la sécurité, l’optimisation ou la pérennité d’un système ou d’un objet."
  },
  {
    "name": "learn",
    "description": "Assimiler de nouvelles données, s’adapter à un contexte ou s’améliorer à partir d’exemples ou d’expériences passées."
  },
  {
    "name": "organize",
    "description": "Structurer, planifier, hiérarchiser ou répartir des éléments dans un but d'efficacité ou de lisibilité."
  }
]

